import { compose, map, range } from '../pkg/rambda.js';
export const id = x => x;
export const isNullish = val => val == null;
export const notNullish = val => !isNullish(val);
export const inRange = numberRange => (val, inclusive = false) => {
  if (isNullish(numberRange)) {
    return false;
  }

  if (inclusive) {
    return val >= numberRange[0] && val <= numberRange[1];
  }

  return val > numberRange[0] && val < numberRange[1];
};
export const isString = x => typeof x === 'string';
export const isObject = x => typeof x === 'object';
export const isArray = x => Array.isArray(x);
export const numberToBooleans = compose(map(_ => false), range(0));
export const maybe = val => {
  const innerValue = val ?? undefined;
  return {
    map: fn => {
      if (isNullish(innerValue)) {
        return maybe();
      }

      return maybe(fn(innerValue));
    },
    value: () => innerValue,
    withDefault: defaultValue => {
      if (isNullish(innerValue)) {
        return defaultValue;
      }

      return innerValue;
    }
  };
};
export const validNumber = num => {
  if (isNullish(num)) return false;
  return !isNaN(num) && isFinite(num);
};